import itertools

class Solution:
    def maxNonDecreasingLength(self, nums1, nums2):
        n = len(nums1)
        best = 0
        for choice in itertools.product((0, 1), repeat=n):
            arr = [nums1[i] if choice[i] == 0 else nums2[i] for i in range(n)]
            cur = 1
            local_best = 1
            for i in range(1, n):
                if arr[i] >= arr[i - 1]:
                    cur += 1
                else:
                    cur = 1
                local_best = max(local_best, cur)
            best = max(best, local_best)
        return best

