var maxNonDecreasingLength = function(nums1, nums2) {
    const n = nums1.length;
    let dp1 = 1, dp2 = 1;
    let best = 1;
    for (let i = 1; i < n; i++) {
        let new1 = 1, new2 = 1;
        if (nums1[i] >= nums1[i - 1]) new1 = Math.max(new1, dp1 + 1);
        if (nums1[i] >= nums2[i - 1]) new1 = Math.max(new1, dp2 + 1);
